    <div style="display:flex;gap:48px;font-size:18px;border-top:1px solid #E8D8D1;padding-top:8px;margin-top:4px"><span style="color:#8E5E4F">Total</span><span style="color:#8E5E4F;font-weight:700">₹${(D.gstEnabled?H:D.total).toFixed(2)}</span></div>
